import Dirty from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('dirty db', () => {
  it('should not emit errors when loading a valid file with data spanning multiple chunks', (done) => {
    const file = path.join(os.tmpdir(), `dirty-test-${process.pid}-${Date.now()}.dirty`);

    const lines: string[] = [];
    for (let i = 0; i < 10000; i++) {
      lines.push(JSON.stringify({ key: `key${i}`, val: `value_${i}_${'a'.repeat(10)}` }));
    }
    const content = lines.join('\n') + '\n';

    fs.writeFileSync(file, content, 'utf-8');

    const errors: Error[] = [];
    const db = new Dirty(file);

    db.on('error', (err: Error) => errors.push(err));

    db.on('load', (size: number) => {
      try {
        expect(errors).toHaveLength(0);
        expect(size).toBe(10000);
        done();
      } catch (e) {
        done(e);
      } finally {
        try { fs.unlinkSync(file); } catch (_) {}
      }
    });
  });
});
