    db.on('load', (size: number) => {
      try {
        expect(errors).toHaveLength(0);
        expect(size).toBe(5000);
        expect(db.get('key00000')).toBe('val0');
        expect(db.get('key04999')).toBe('val4999');
        done();
      } catch (e) {
        done(e);
      } finally {
        try { fs.unlinkSync(file); } catch (_) {}
      }
    });
  });
});
